function makeConceptFableLensStory(fable) {
  const field = getFieldByCode(fable.selectedFieldCode);
  const { category, group } = getCategoryGroupForField(field);
  const imageSource = getPublishedStoryImageSource(category, group, field) || {};
  const fieldCode = field?.code || fable.selectedFieldCode || "";
  const fieldTitleZh = field?.titleZh || field?.title || fable.conceptNameZh || fable.titleZh || fable.id;
  return {
    id: fable.id,
    storyLevel: "concept-fable",
    categoryCode: category?.code || fable.categoryCode || "00",
    groupCode: group?.code || "",
    groupTitle: group?.title || "",
    groupTitleZh: group?.chineseTitle || group?.title || "",
    fieldCodes: fieldCode ? [fieldCode] : [],
    fieldTitlesZh: fieldCode ? { [fieldCode]: fieldTitleZh } : {},
    image: imageSource.image || "/assets/stories/000-general-starter-course.png",
    imageAlt: imageSource.imageAlt || "A MapKAI concept story connected to a knowledge lens.",
    imageAltZh: imageSource.imageAltZh || "一个连接 MapKAI 知识镜头的概念故事。",
    imageInheritedFromGroup: true,
    title: fable.title || fable.conceptName || fable.id,
    titleZh: fable.titleZh || fable.conceptNameZh || fable.title || fable.id,
    summary: fable.summary || fable.reveal || fable.explanation || "",
    summaryZh: fable.summaryZh || fable.revealZh || fable.explanationZh || "",
    scene: fable.scene || fable.summary || "",
    sceneZh: fable.sceneZh || fable.summaryZh || "",
    storyBody: fable.storyBody || fable.summary || "",
    storyBodyZh: fable.storyBodyZh || fable.summaryZh || "",
    support: "",
    supportZh: "",
    knowledgePoint: fable.knowledgePoint || fable.explanation || fable.reveal || "",
    knowledgePointZh: fable.knowledgePointZh || fable.explanationZh || fable.revealZh || "",
    reflectionQuestion: fable.reflectionQuestion || "",
    reflectionQuestionZh: fable.reflectionQuestionZh || fable.reflectionQuestion || "",
    tags: fable.tags || [fable.conceptName || fable.title || "concept fable"],
    tagsZh: fable.tagsZh || [fable.conceptNameZh || fable.titleZh || "概念寓言"],
    sourceConceptFableId: fable.id,
    sourceConceptFableRoute: `/concept-fables/${fable.id}`,
    originalConceptFable: fable,
  };
}

function addConceptFablesToLensStories() {
  if (!arePublicArticlesVisible()) return [];
  const nextStories = [];
  conceptFables.forEach((fable) => {
    if (lensStories.some((story) => story.id === fable.id)) return;
    const lensStory = makeConceptFableLensStory(fable);
    nextStories.push(lensStory);
    lensStories.push(lensStory);
  });
  return nextStories;
}

function getGptBatchSourceStoryId(story) {
  if (!story) return "";
  if (story.sourceStoryId) return story.sourceStoryId;
  if (story.sourceConceptFableId) return story.sourceConceptFableId;
  const id = story.id || "";
  return id.startsWith(publishedStoryLensIdPrefix) ? id.slice(publishedStoryLensIdPrefix.length) : id;
}

function isGptBatchLensStory(story) {
  if (story?.storyLevel === "subject-intro") return true;
  return gptBatchStoryIds.has(getGptBatchSourceStoryId(story));
}

function removeNonGptBatchLensStories() {
  for (let index = lensStories.length - 1; index >= 0; index -= 1) {
    if (!isGptBatchLensStory(lensStories[index])) lensStories.splice(index, 1);
  }
}

function getActiveBaseLensStories() {
  if (!arePublicArticlesVisible()) return [];
  if (publishedStoryLensStories.length) return publishedStoryLensStories;
  return baseLensStories.map((story) => getLensStoryById(story.id) || story);
}

function getLensStoryForGroup(categoryCode, groupCode) {
  if (!arePublicArticlesVisible()) return null;
  return lensStories.find((story) => story.categoryCode === categoryCode && story.groupCode === groupCode && story.storyLevel !== "field");
}

function getLensStoryPriority(story) {
  if (story?.storyLevel === "subject-intro") return -1;
  if (story?.storyLevel === "published-story") return 0;
  if (story?.storyLevel === "field") return 1;
  if (story?.storyLevel === "group") return 2;
  return 3;
}

function sortLensStoriesByStoryFirst(a, b) {
  const priorityDiff = getLensStoryPriority(a) - getLensStoryPriority(b);
  if (priorityDiff) return priorityDiff;
  return getLensStoryValue(a, "title").localeCompare(getLensStoryValue(b, "title"));
}

function getLensStoriesForField(categoryCode, groupCode, fieldCode) {
  if (!arePublicArticlesVisible()) return [];
  return lensStories
    .filter((story) =>
      story.categoryCode === categoryCode &&
      story.groupCode === groupCode &&
      Array.isArray(story.fieldCodes) &&
      story.fieldCodes.includes(fieldCode)
    )
    .sort(sortLensStoriesByStoryFirst);
}

function getLensStoryForField(categoryCode, groupCode, fieldCode) {
  return getLensStoriesForField(categoryCode, groupCode, fieldCode)[0] || null;
}

function getLensStoryValue(story, key) {
  if (!story) return "";
  if (currentLanguage === "zh") return story[`${key}Zh`] || story[key] || "";
  return story[key] || "";
}

function getLensStoryList(story, key) {
  if (!story) return [];
  if (currentLanguage === "zh") return story[`${key}Zh`] || story[key] || [];
  return story[key] || [];
}

function getLensStoryFieldTitle(story, code, fallbackTitle) {
  if (currentLanguage === "zh") return story?.fieldTitlesZh?.[code] || fallbackTitle;
  return fallbackTitle;
}

function getConceptFableById(fableId) {
  if (!arePublicArticlesVisible()) return null;
  return conceptFables.find((fable) => fable.id === fableId);
}

function getConceptFableForCategory(categoryCode) {
  if (!arePublicArticlesVisible()) return null;
  return conceptFables.find((fable) => fable.categoryCode === categoryCode);
}

function getConceptFableValue(fable, key) {
  if (!fable) return "";
  if (currentLanguage === "zh") return fable[`${key}Zh`] || fable[key] || "";
  return fable[key] || "";
}

function getConceptFableList(fable, key) {
  if (!fable) return [];
  if (currentLanguage === "zh") return fable[`${key}Zh`] || fable[key] || [];
  return fable[key] || [];
}

function getConceptFableCategoryTitle(fable) {
  const category = categories.find((item) => item.code === fable.categoryCode);
  if (!category) return fable.categoryCode || "";
  return getPublicCategoryTitle(category);
}

function normalizeRatingSummary(summary) {
  if (!summary?.storyId) return null;
  return {
    storyId: summary.storyId,
    averageRating: Number(summary.averageRating || 0),
    ratingCount: Number(summary.ratingCount || 0),
  };
}

function mergeStoryRatingSummary(summary) {
  const normalized = normalizeRatingSummary(summary);
  if (!normalized) return;
  storyRatingSummaries[normalized.storyId] = normalized;
}

function getLocalStoryRatings() {
  try {
    const stored = JSON.parse(localStorage.getItem(storyRatingsKey) || "{}");
    return stored && typeof stored === "object" && !Array.isArray(stored) ? stored : {};
  } catch {
    return {};
  }
}

function setLocalStoryRating(storyId, rating) {
  const ratings = getLocalStoryRatings();
  ratings[storyId] = {
    rating,
    updatedAt: new Date().toISOString(),
  };
  localStorage.setItem(storyRatingsKey, JSON.stringify(ratings));
}

function getUserStoryRating(storyId) {
  return Number(getLocalStoryRatings()[storyId]?.rating || 0);
}

function makeRatingArticle({ id, title, summary, href, categoryTitle, kind }) {
  if (!id || !href) return null;
  return {
    id,
    title: title || id,
    summary: summary || "",
    href,
    categoryTitle: categoryTitle || "",
    kind: kind || t("storiesEyebrow"),
  };
}

function getRatingArticleForConceptFable(fable) {
  if (!fable) return null;
  return makeRatingArticle({
    id: `concept-fable:${fable.id}`,
    title: getConceptFableValue(fable, "title"),
    summary: getConceptFableValue(fable, "summary"),
    href: `/concept-fables/${fable.id}`,
    categoryTitle: getConceptFableCategoryTitle(fable),
    kind: t("conceptFablesEyebrow"),
  });
}

function getRatingArticleForLensStory(story) {
  if (!story) return null;
  if (story.originalConceptFable || story.sourceConceptFableId) {
    const fable = story.originalConceptFable || conceptFables.find((item) => item.id === story.sourceConceptFableId || item.id === story.id);
    return getRatingArticleForConceptFable(fable);
  }
  const category = categories.find((item) => item.code === story.categoryCode);
  const sourceStoryId = story.sourceStoryId || "";
  return makeRatingArticle({
    id: sourceStoryId ? `published-story:${sourceStoryId}` : `lens-story:${story.id}`,
    title: getLensStoryValue(story, "title"),
    summary: getLensStoryValue(story, "summary"),
    href: sourceStoryId ? publishedStoryLensRoutesByStoryId[sourceStoryId] || `/lens-stories/${story.id}` : `/lens-stories/${story.id}`,
    categoryTitle: category ? getPublicCategoryTitle(category) : "",
    kind: story.storyLevel === "subject-intro" ? t("submoduleIntroStory") : t("lensStoryEyebrow"),
  });
}

function getRatingArticleForPublishedStory(story) {
  if (!story) return null;
  return makeRatingArticle({
    id: `published-story:${story.id}`,
    title: getStoryTitle(story),
    summary: getStorySummary(story),
    href: publishedStoryLensRoutesByStoryId[story.id] || `/lens-stories/${getPublishedStoryLensId(story)}`,
    categoryTitle: "",
    kind: t("storiesEyebrow"),
  });
}

function getAllRateableArticles() {
  if (!arePublicArticlesVisible()) return [];
  const articlesById = new Map();
  conceptFables.forEach((fable) => {
    const article = getRatingArticleForConceptFable(fable);
    if (article) articlesById.set(article.id, article);
  });
  lensStories.forEach((story) => {
    const article = getRatingArticleForLensStory(story);
    if (article && !articlesById.has(article.id)) articlesById.set(article.id, article);
  });
  getPublishedStories().forEach((story) => {
    const article = getRatingArticleForPublishedStory(story);
    if (article && !articlesById.has(article.id)) articlesById.set(article.id, article);
  });
  return Array.from(articlesById.values());
}

function getRateableArticleById(storyId) {
  return getAllRateableArticles().find((article) => article.id === storyId) || null;
}

function getStoryRatingSummary(storyId) {
  const savedSummary = storyRatingSummaries[storyId];
  const userRating = getUserStoryRating(storyId);
  if (savedSummary?.ratingCount) return savedSummary;
  return userRating ? { storyId, averageRating: userRating, ratingCount: 1 } : { storyId, averageRating: 0, ratingCount: 0 };
}

function formatAverageRating(value) {
  const rating = Number(value || 0);
  return rating ? rating.toFixed(1).replace(/\.0$/, "") : "0";
}

function getLocalTopRatedStorySummaries() {
  return Object.entries(getLocalStoryRatings())
    .map(([storyId, item]) => ({
      storyId,
      averageRating: Number(item.rating || 0),
      ratingCount: item.rating ? 1 : 0,
    }))
    .filter((item) => item.ratingCount > 0);
}

function getTopRatedStorySummaries() {
  const source = storyRatingTopList.length ? storyRatingTopList : getLocalTopRatedStorySummaries();
  return source
    .map(normalizeRatingSummary)
    .filter((summary) => summary && getRateableArticleById(summary.storyId))
    .sort((a, b) => {
      const averageDiff = b.averageRating - a.averageRating;
      if (averageDiff) return averageDiff;
      return b.ratingCount - a.ratingCount;
    })
    .slice(0, 5);
}

function renderStoryRatingPanel(article) {
  if (!article?.id || !arePublicArticlesVisible()) return "";
  const summary = getStoryRatingSummary(article.id);
  const userRating = getUserStoryRating(article.id);
  const average = formatAverageRating(summary.averageRating);
  const averageText = summary.ratingCount ? t("ratingAverage", average, summary.ratingCount) : t("ratingNoAverage");
  const buttons = [1, 2, 3, 4, 5].map((score) => `
    <button class="${userRating === score ? "is-selected" : ""}" type="button" data-rate-story="${escapeHtml(article.id)}" data-rating-value="${score}" aria-pressed="${userRating === score}">
      <span>${score}</span>
    </button>`).join("");

  return `
    <section class="story-rating-panel" data-story-rating-panel data-story-id="${escapeHtml(article.id)}">
      <div>
        <span>${escapeHtml(t("ratingTitle"))}</span>
        <h2>${escapeHtml(article.title)}</h2>
        <p>${escapeHtml(t("ratingCopy"))}</p>
      </div>
      <div class="story-rating-controls" aria-label="${escapeHtml(t("ratingChoose"))}">
        ${buttons}
      </div>
      <p class="story-rating-summary">${escapeHtml(averageText)}${userRating ? ` · ${escapeHtml(t("ratingYourScore", userRating))}` : ""}</p>
      ${storyRatingStatus ? `<p class="story-rating-status">${escapeHtml(storyRatingStatus)}</p>` : ""}
    </section>`;
}

function renderStoryRatingPanels() {
  document.querySelectorAll("[data-story-rating-panel]").forEach((panel) => {
    const article = getRateableArticleById(panel.dataset.storyId || "");
    if (article) panel.outerHTML = renderStoryRatingPanel(article);
  });
}

function renderTopRatedStories() {
  const target = document.getElementById("topRatedStories");
  if (!target) return;
  if (!arePublicArticlesVisible()) {
    target.hidden = true;
    target.innerHTML = "";
    return;
  }
  const summaries = getTopRatedStorySummaries();
  if (!summaries.length) {
    target.hidden = true;
    target.innerHTML = "";
    return;
  }
  target.hidden = false;
  const cards = summaries.map((summary, index) => {
    const article = getRateableArticleById(summary.storyId);
    const average = formatAverageRating(summary.averageRating);
    return `
      <a class="top-rated-story-card" href="${escapeHtml(article.href)}" data-route="${escapeHtml(article.href)}">
        <small>${index + 1} · ${escapeHtml(article.kind)}${article.categoryTitle ? ` · ${escapeHtml(article.categoryTitle)}` : ""}</small>
        <strong>${escapeHtml(article.title)}</strong>
        <span>${escapeHtml(t("topRatedAverage", average, summary.ratingCount))}</span>
        <em>${escapeHtml(t("topRatedOpen"))}</em>
      </a>`;
  }).join("");

  target.innerHTML = `
    <div class="section-heading compact">
      <p class="eyebrow">${escapeHtml(t("topRatedEyebrow"))}</p>
      <h2>${escapeHtml(t("topRatedTitle"))}</h2>
      <p>${escapeHtml(t("topRatedCopy"))}</p>
    </div>
    <div class="top-rated-story-grid">${cards}</div>`;
}

async function loadStoryRatings() {
  if (!arePublicArticlesVisible()) {
    renderTopRatedStories();
    return;
  }
  try {
    const response = await fetch("/api/story-ratings?limit=5", { cache: "no-store" });
    if (!response.ok) throw new Error("Story rating API unavailable");
    const data = await response.json();
    (data.summaries || []).forEach(mergeStoryRatingSummary);
    storyRatingTopList = (data.top || []).map(normalizeRatingSummary).filter(Boolean);
    storyRatingsLoaded = true;
  } catch {
    storyRatingTopList = getLocalTopRatedStorySummaries();
    storyRatingsLoaded = true;
  }
  renderTopRatedStories();
  renderStoryRatingPanels();
}

async function loadStoryRatingForArticle(storyId) {
  if (!arePublicArticlesVisible() || !storyId) return;
  try {
    const query = new URLSearchParams({
      storyId,
      visitorId: getVisitorId(),
      limit: "5",
    });
    const response = await fetch(`/api/story-ratings?${query}`, { cache: "no-store" });
    if (!response.ok) throw new Error("Story rating API unavailable");
    const data = await response.json();
    (data.summaries || []).forEach(mergeStoryRatingSummary);
    storyRatingTopList = (data.top || []).map(normalizeRatingSummary).filter(Boolean);
    const userRating = Number(data.userRatings?.[storyId] || 0);
    if (userRating) setLocalStoryRating(storyId, userRating);
  } catch {
    // The local rating stays visible if the API is not available in development.
  }
  renderStoryRatingPanels();
  renderTopRatedStories();
}

async function rateStory(storyId, rating) {
  const article = getRateableArticleById(storyId);
  if (!article || !rating) return;
  setLocalStoryRating(storyId, rating);
  storyRatingStatus = t("ratingLocalSaved");
  renderStoryRatingPanels();
  renderTopRatedStories();

  try {
    const response = await fetch("/api/story-ratings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        storyId,
        rating,
        visitorId: getVisitorId(),
        pagePath: window.location.pathname,
        language: currentLanguage,
      }),
    });
    if (!response.ok) throw new Error("Story rating API unavailable");
    const data = await response.json();
    mergeStoryRatingSummary(data.summary);
    storyRatingTopList = (data.top || []).map(normalizeRatingSummary).filter(Boolean);
    storyRatingStatus = t("ratingSaved");
  } catch {
    storyRatingTopList = getLocalTopRatedStorySummaries();
  }

  renderStoryRatingPanels();
  renderTopRatedStories();
}

function getStoryFieldCodes(story) {
  return Array.from(new Set([story.mainField, ...(story.activatedFields || [])].filter(Boolean)));
}

function getValidatedStoryFields(story) {
  const allFieldIds = getStoryFieldCodes(story);
  const matched = [];
  const unmatched = [];
  allFieldIds.forEach((fieldId) => {
    const field = getFieldById(fieldId);
    if (field) matched.push(field);
    else unmatched.push(fieldId);
  });
  return { matched, unmatched };
}

function getStoryUnmatchedFields(story) {
  return getValidatedStoryFields(story).unmatched;
}

function getStoriesForField(fieldIdOrCode) {
  const field = getFieldById(fieldIdOrCode);
  if (!field) return [];
  return getPublishedStories().filter((story) => getStoryFieldCodes(story).includes(field.id));
}

function getStoryById(storyId) {
  return getPublishedStories().find((story) => story.id === storyId);
}

function getStoryTeaser(story) {
  const body = story.storyBody || story.summary || "";
  const firstSentence = body.match(/^[^.!?。！？]+[.!?。！？]/)?.[0] || body;
  return firstSentence.length > 180 ? `${firstSentence.slice(0, 177).trim()}...` : firstSentence;
}

function getStoryPublicTags(story) {
  if (story.id === "broad-street-pump") return ["Public Health", "Evidence", "Infrastructure", "Governance"];
  if (story.id === "challenger-launch-decision") return ["Engineering", "Risk", "Management", "Ethics"];
  if (story.id === "cuban-missile-crisis-excomm") return ["Crisis", "Diplomacy", "Military", "Communication"];
  return (story.coreConcepts || []).slice(0, 4).map((tag) => tag.replace(/\b\w/g, (letter) => letter.toUpperCase()));
}

function getLitFieldCodes() {
  return new Set(
    getPublishedStories()
      .flatMap((story) => getValidatedStoryFields(story).matched)
      .map((field) => field.id)
  );
}

function getConnectedFields(fieldIdOrCode) {
  const field = getFieldById(fieldIdOrCode);
  if (!field) return [];
  const connected = new Set();
  getStoriesForField(field.id).forEach((story) => {
    getStoryFieldCodes(story).forEach((code) => {
      if (code !== field.id) connected.add(code);
    });
  });
  return Array.from(connected).map(getFieldById).filter(Boolean);
}

function getCoverageStats() {
  const fields = getKnowledgeFields();
  const litFields = getLitFieldCodes();
  const published = getPublishedStories();
  const activatedTotal = published.reduce((total, story) => total + getValidatedStoryFields(story).matched.length, 0);
  return {
    officialAreas: knowledgeAreas.filter((area) => area.code !== "99").length,
    areasIncludingSpecial: knowledgeAreas.length,
    narrowFields: knowledgeNarrowFields.length,
    detailedFieldsExcludingUnknown: knowledgeFields.filter((field) => field.code !== "9999").length,
    detailedFieldsIncludingUnknown: knowledgeFields.length,
    totalPracticalFields: fields.length,
    administrativeFields: knowledgeFields.filter((field) => field.isAdministrative).length,
    litFields: fields.filter((field) => litFields.has(field.id)).length,
    unlitFields: fields.filter((field) => !litFields.has(field.id)).length,
    publishedStories: published.length,
    averageActivatedFields: published.length ? activatedTotal / published.length : 0,
    unmatchedStoryFields: published.flatMap(getStoryUnmatchedFields),
  };
}

